  var row = Math.floor(idx / cols);

  var x = pad + col*(w+gap);
  var y = pad + row*(h+8);

  // keep in bounds
  var maxX = Math.max(pad, zoneW - w - pad);
  x = clamp(x, pad, maxX);
  y = Math.max(pad, y);
  return {x:x,y:y};
}

